import{_ as a,o as p,c as n,ag as e}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"第一次完整运行","description":"","frontmatter":{},"headers":[],"relativePath":"guide/first-run.md","filePath":"guide/first-run.md"}'),i={name:"guide/first-run.md"};function t(l,s,o,r,c,d){return p(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="第一次完整运行" tabindex="-1">第一次完整运行 <a class="header-anchor" href="#第一次完整运行" aria-label="Permalink to &quot;第一次完整运行&quot;">​</a></h1><p>假设现在是周三下午，你突然想写点东西。</p><p>你想写什么？随便你定。但为了让你好理解，我先假设一个具体的场景——你跟着我走一遍，看完你就知道整个流程是怎么回事了。</p><hr><h2 id="场景设定" tabindex="-1">场景设定 <a class="header-anchor" href="#场景设定" aria-label="Permalink to &quot;场景设定&quot;">​</a></h2><p>我们要写的是这样一篇笔记：</p><blockquote><p><strong>主题</strong>：程序员如何用 AI 高效做周报 <strong>角度</strong>：从 2 小时压缩到 10 分钟 <strong>CTA</strong>：评论你的周报痛点，送你一个自动化脚本</p></blockquote><p>这就是我们这趟旅程的目的地。</p><p>在整个过程中，我会告诉你：</p><ul><li>AI 在做什么</li><li>你需要做什么</li><li>可能遇到什么问题</li><li>怎么解决</li></ul><p>准备好了？我们走。</p><hr><h2 id="开始之前" tabindex="-1">开始之前 <a class="header-anchor" href="#开始之前" aria-label="Permalink to &quot;开始之前&quot;">​</a></h2><p>先确保你已经跑过 <code>xhsops init</code>，以及填好了那 5 个 brand 文件。</p><p>如果没有，回过头去，花 5 分钟搞定再回来。我在这里等你。</p><p>好了？好，我们开始。</p><hr><h2 id="第一步-发起-quick" tabindex="-1">第一步：发起 quick <a class="header-anchor" href="#第一步-发起-quick" aria-label="Permalink to &quot;第一步：发起 quick&quot;">​</a></h2><p>打开你的 AI 工具（Claude Code、Cursor、Windsurf，哪个顺手用哪个），直接说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:quick</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主题：程序员如何用 AI 高效做周报</span></span>
<span class="line"><span>角度：从 2 小时压缩到 10 分钟</span></span>
<span class="line"><span>CTA：评论你的周报痛点，送你一个自动化脚本</span></span></code></pre></div><p>或者更自然一点，像这样：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我写一篇关于程序员用 AI 做周报的笔记</span></span></code></pre></div><p>都行。AI 听得懂人话。</p><p><strong>这时候 AI 在做什么？</strong></p><p>它在后台调用 XHSOps 的工作流系统。它会：</p><ol><li>读取你的品牌配置——它要知道你是谁、你对谁说话、你的风格是什么</li><li>解析你给的主题和角度——它要理解你想表达什么</li><li>在 <code>.xhsops/quick/</code> 下面创建一个新的工作目录——名字会是一串时间戳，比如 <code>20260313-143022</code></li><li>生成 <code>brief.md</code>——这是「我要怎么写」的计划书</li><li>生成 <code>draft.md</code>——这是第一版初稿</li></ol><p>你不需要管这些文件具体在哪。AI 会帮你找到它，你需要看的时候它会展示给你。</p><p><strong>你会看到什么？</strong></p><p>打开工作目录，你会看到类似这样的结构：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.xhsops/quick/20260313-143022/</span></span>
<span class="line"><span>├── brief.md      # 写作计划</span></span>
<span class="line"><span>├── draft.md      # 初稿</span></span>
<span class="line"><span>└── metadata.json # 元信息</span></span></code></pre></div><p>可能还会有其他文件，但一开始你主要看这两个。</p><hr><h2 id="第二步-看初稿-提意见" tabindex="-1">第二步：看初稿，提意见 <a class="header-anchor" href="#第二步-看初稿-提意见" aria-label="Permalink to &quot;第二步：看初稿，提意见&quot;">​</a></h2><p>等一会儿，AI 就把初稿写出来了。</p><p>你会看到一篇完整的笔记，可能有一千多字。它分了开头、中间、结尾，有例子，有槽点，有干货。</p><p>但是，你也会看到一些 <code>&lt;placeholder&gt;...&lt;/placeholder&gt;</code> 的标记。</p><p>这是什么东西？</p><p>这是 AI 告诉你：「这个地方我没想好，想听听你的意见。」</p><p>可能是在某个例子上——「这里用什么例子更好？」</p><p>可能是某个观点上——「这句话是不是太绝对了？」</p><p>可能是 CTA 上——「这样引导互动够不够？」</p><p><strong>你该怎么做？</strong></p><p>很简单，直接说：</p><ul><li>「这个例子换成程序员日常会更贴切」</li><li>「第三段可以更直接一点，别绕弯子」</li><li>「CTA 放到最后吧，别在中间打断」</li></ul><p>或者更懒一点：</p><ul><li>「第二段帮我改得更口语化一点」</li><li>「开头可以更有冲击力一点」</li></ul><p>AI 会根据你的意见生成新版本。</p><p>这个过程可以来回好几轮。你可能会说「再来一版」「还是第一版好」「把这两版结合起来」——怎么都行，没有对错。</p><p><strong>Tips：怎么提意见更有效？</strong></p><ol><li><strong>具体一点</strong>——「第三段」比「中间那部分」更管用</li><li><strong>方向给出来</strong>——「更有趣」不如「加个程序员的梗」</li><li><strong>别一次给太多</strong>——一次改一件事，AI 更容易理解你的意思</li></ol><hr><h2 id="第三步-审核" tabindex="-1">第三步：审核 <a class="header-anchor" href="#第三步-审核" aria-label="Permalink to &quot;第三步：审核&quot;">​</a></h2><p>稿子看得差不多了，你觉得方向对、内容也有干货了。现在进入审核阶段。</p><p>你说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:review</span></span></code></pre></div><p>或者：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我审核这篇</span></span></code></pre></div><p><strong>AI 在做什么？</strong></p><p>它在根据一套规则检查你的稿子。这些规则来自两个方面：</p><ol><li><strong>小红书的最佳实践</strong>——开头能不能抓住人、结构清不清晰、CTA 放的位置合不合理</li><li><strong>你的品牌配置</strong>——语气对不对、是不是在说该说的事、是不是避开了不该说的</li></ol><p>然后它会生成一个 <code>review.md</code>，里面会有类似这样的内容：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## 审核结果</span></span>
<span class="line"><span></span></span>
<span class="line"><span>✅ 通过</span></span>
<span class="line"><span>- 开头抓住了痛点</span></span>
<span class="line"><span>- 结构清晰，3 个步骤很清楚</span></span>
<span class="line"><span>- CTA 位置合适</span></span>
<span class="line"><span></span></span>
<span class="line"><span>⚠️ 建议修改</span></span>
<span class="line"><span>- 第三段的例子有点旧，换成今年的案例更好</span></span>
<span class="line"><span>- 结尾可以再强化一下 CTA</span></span>
<span class="line"><span></span></span>
<span class="line"><span>❌ 需要修改</span></span>
<span class="line"><span>- 还有 2 个 placeholder 没填完</span></span></code></pre></div><p><strong>你该怎么做？</strong></p><p>如果全是 ✅，那太好了，直接进入下一步。</p><p>如果有 ⚠️ 或 ❌，你来说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>根据 review 意见帮我改一下</span></span></code></pre></div><p>或者：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:iterate</span></span></code></pre></div><p>然后 AI 会生成新版本的 draft。</p><p>这个循环可以跑好几轮——review → iterate → review → iterate——直到没有任何警告。</p><hr><h2 id="第四步-生成发布包" tabindex="-1">第四步：生成发布包 <a class="header-anchor" href="#第四步-生成发布包" aria-label="Permalink to &quot;第四步：生成发布包&quot;">​</a></h2><p>稿子定稿了，终于到了最爽的时刻。</p><p>你说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:publish</span></span></code></pre></div><p>或者：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我生成发布包</span></span></code></pre></div><p><strong>AI 在做什么？</strong></p><p>这回它不再只是给你一篇文档了。它会生成一个完整的发布包，里面包含：</p><ol><li><strong>终稿正文</strong>——可以直接复制粘贴到小红书的编辑器里</li><li><strong>封面方向</strong>——建议的标题、关键词、标签</li><li><strong>配图建议</strong>——哪里应该配什么图，配什么风格</li><li><strong>发布检查清单</strong>——发之前再确认一遍的条目</li></ol><p>你会得到一个文件夹，大概长这样：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.xhsops/quick/20260313-143022/publish/</span></span>
<span class="line"><span>├── final-draft.md        # 终稿</span></span>
<span class="line"><span>├── cover-suggestion.md    # 封面建议</span></span>
<span class="line"><span>├── image-plan.md         # 配图计划</span></span>
<span class="line"><span>└── checklist.md         # 发布检查清单</span></span></code></pre></div><p><strong>你该怎么做？</strong></p><p>打开 <code>final-draft.md</code>，复制全部内容，打开小红书编辑器，粘贴。</p><p>然后根据 <code>cover-suggestion.md</code> 起标题、想封面。</p><p>根据 <code>image-plan.md</code> 找图或作图。</p><p>最后对照 <code>checklist.md</code> 逐项确认。</p><p>全部搞定，点发布。</p><hr><h2 id="第五步-归档" tabindex="-1">第五步：归档 <a class="header-anchor" href="#第五步-归档" aria-label="Permalink to &quot;第五步：归档&quot;">​</a></h2><p>发布成功了！这篇笔记已经躺在你的主页里了。</p><p>但是还没完。最后一步，我们归档。</p><p>你说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:archive</span></span></code></pre></div><p>或者：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我归档</span></span></code></pre></div><p><strong>AI 在做什么？</strong></p><p>它会做几件事：</p><ol><li>把这次创作的过程文件整理好——不是删除，而是归档到一个更整齐的地方</li><li>提取这次的经验教训——什么样的开头有效、什么样的 CTA 效果好、什么角度读者更喜欢</li><li>把这些经验写进 <code>.xhsops/knowledge/winning-patterns.md</code></li></ol><p>下次 AI 帮你写新内容的时候，它会主动参考这些经验。</p><p>这就是 XHSOps 最迷人的地方——不是「聊完就结束」，而是<strong>每一次都在积累</strong>。</p><hr><h2 id="跑完了-感受如何" tabindex="-1">跑完了，感受如何？ <a class="header-anchor" href="#跑完了-感受如何" aria-label="Permalink to &quot;跑完了，感受如何？&quot;">​</a></h2><p>如果完整走一遍，你会发现几个不一样的地方：</p><ol><li><p><strong>每一步都有文件</strong>——不是聊完就消失，过程都留得住。下次想回头看当时的初稿、当时的审核意见，都能找得到。</p></li><li><p><strong>发布是独立的一步</strong>——不是「聊完就发」，而是生成一个可以直接用的包。终稿、配图、封面、清单，分得清清楚楚。</p></li><li><p><strong>经验会积累</strong>——archive 不是结束，是下一次更好的开始。你的内容会越写越好，AI 会越来越懂你。</p></li><li><p><strong>你是主角</strong>——整个过程，你都在和 AI 对话。AI 是你的助手，你是指挥官。它帮你干活，但你拿主意。</p></li></ol><hr><h2 id="可能会卡住的地方" tabindex="-1">可能会卡住的地方 <a class="header-anchor" href="#可能会卡住的地方" aria-label="Permalink to &quot;可能会卡住的地方&quot;">​</a></h2><p>别担心，这不是 bug，是系统在保护你。</p><p><strong>brand 没填完</strong> → 系统会报错提示你补。回去把 5 个文件填了再来。</p><p><strong>draft 还有 placeholder</strong> → 先补完才能 review。你可以在 AI 的帮助下填，也可以自己直接改。</p><p><strong>review 没写完</strong> → 先完成审核才能进入下一阶段。这是为你好，带着半成品赶路，最后收拾起来更麻烦。</p><p><strong>审核没通过</strong> → 按照意见改，改到通过为止。系统不会让你带着问题进入下一环节。</p><p>这些「卡住」不是刁难，是系统在告诉你：先把眼前的活干完，别带着半成品赶路。</p><hr><h2 id="接下来" tabindex="-1">接下来 <a class="header-anchor" href="#接下来" aria-label="Permalink to &quot;接下来&quot;">​</a></h2><p>现在你已經知道一个完整的 quick 流程怎么跑了。</p><p>你可以自己试着走一遍。找一个想写的主题，试着用 XHSOps 跑完整个流程。</p><p>如果想了解更多：</p><ul><li><strong>Quick、Trend、Campaign 怎么选</strong> → 不同的场景用不同的工作流</li><li><strong>项目结构长什么样</strong> → 深入了解 <code>.xhsops/</code> 里面到底有什么</li><li><strong>Brand 怎么写更好</strong> → 让 AI 更懂你，写出来的东西更有你本人的味道</li></ul><p>有问题随时回来翻文档，或者直接问 AI。</p><p>跑起来吧。</p>`,121)])])}const u=a(i,[["render",t]]);export{g as __pageData,u as default};
